BEGIN IMMEDIATE;
CREATE TEMP TABLE duplicate_repair_expected AS
SELECT COUNT(*) AS expected_duplicate_count
FROM (SELECT order_id FROM orders_raw
      WHERE load_batch IN ('batch-2026-07-10-01', 'batch-2026-07-10-02')
      GROUP BY order_id
      HAVING COUNT(*) = 2 AND COUNT(DISTINCT load_batch) = 2);
CREATE TEMP TABLE duplicate_repair_rows (rowid INTEGER PRIMARY KEY);
INSERT INTO duplicate_repair_rows
SELECT suspect.rowid FROM orders_raw AS suspect
WHERE suspect.load_batch = 'batch-2026-07-10-02'
  AND EXISTS (SELECT 1 FROM orders_raw AS keeper
              WHERE keeper.order_id = suspect.order_id
                AND keeper.load_batch = 'batch-2026-07-10-01');
SELECT COUNT(*) AS candidate_rows, expected_duplicate_count,
       COUNT(*) = expected_duplicate_count AS count_matches
FROM duplicate_repair_rows, duplicate_repair_expected;
CREATE TEMP TABLE duplicate_repair_gate
  (check_name TEXT, passed INTEGER NOT NULL CHECK (passed = 1));
INSERT OR ROLLBACK INTO duplicate_repair_gate
SELECT 'candidate count', COUNT(*) = expected_duplicate_count
FROM duplicate_repair_rows, duplicate_repair_expected;
CREATE TABLE orders_raw_restore_20260710_02 AS
SELECT suspect.* FROM orders_raw AS suspect
JOIN duplicate_repair_rows AS doomed ON doomed.rowid = suspect.rowid;
DELETE FROM orders_raw
WHERE EXISTS (SELECT 1 FROM duplicate_repair_rows AS doomed
              WHERE doomed.rowid = orders_raw.rowid);
SELECT changes() AS deleted_rows;
SELECT COUNT(*) AS remaining_cross_batch_duplicates
FROM (SELECT order_id FROM orders_raw
      WHERE load_batch IN ('batch-2026-07-10-01', 'batch-2026-07-10-02')
      GROUP BY order_id HAVING COUNT(DISTINCT load_batch) = 2);
INSERT OR ROLLBACK INTO duplicate_repair_gate
SELECT 'final duplicate count', COUNT(*) = 0
FROM (SELECT order_id FROM orders_raw
      WHERE load_batch IN ('batch-2026-07-10-01', 'batch-2026-07-10-02')
      GROUP BY order_id HAVING COUNT(DISTINCT load_batch) = 2);
DROP TABLE duplicate_repair_gate;
DROP TABLE duplicate_repair_rows;
DROP TABLE duplicate_repair_expected;
COMMIT;

